import React, { useState, useEffect } from 'react';
import { FiSearch, FiTrash2, FiEdit2, FiEye, FiFilter } from 'react-icons/fi';
import axios from 'axios';
import { toast } from 'react-hot-toast';

const JobManagement = () => {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  useEffect(() => {
    fetchJobs();
  }, []);

  const fetchJobs = async () => {
    try {
      const res = await axios.get('/api/jobs');
      setJobs(res.data);
    } catch (err) {
      toast.error('Failed to load jobs');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteJob = async (id) => {
    if (!window.confirm('Are you sure you want to delete this job?')) return;
    try {
      await axios.delete(`/api/jobs/${id}`);
      toast.success('Job deleted successfully');
      fetchJobs();
    } catch (err) {
      toast.error('Failed to delete job');
    }
  };

  const filteredJobs = jobs.filter(j => 
    j.title.toLowerCase().includes(search.toLowerCase()) || 
    j.category.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between bg-surface p-4 rounded-xl border border-outline shadow-sm font-body">
        <div className="relative w-96">
          <FiSearch className="absolute left-3 top-1/2 -translate-y-1/2 text-ink-3" />
          <input 
            type="text" 
            placeholder="Search jobs by title or category..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="input pl-10 h-10 text-sm"
          />
        </div>
        <div className="flex gap-2">
          <div className="relative">
            <select className="input h-10 pl-10 pr-8 text-xs appearance-none">
              <option>All Statuses</option>
              <option>Open</option>
              <option>In Progress</option>
              <option>Completed</option>
            </select>
            <FiFilter className="absolute left-3 top-1/2 -translate-y-1/2 text-ink-3" />
          </div>
        </div>
      </div>

      <div className="card overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-surface-alt border-b border-outline">
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-ink-3">Job Details</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-ink-3">Category</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-ink-3">Budget</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-ink-3">Status</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-ink-3 text-right">Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredJobs.length > 0 ? filteredJobs.map((job) => (
              <tr key={job._id} className="border-b border-outline hover:bg-canvas-alt transition-colors">
                <td className="px-6 py-4">
                  <div>
                    <p className="font-semibold text-ink h-name italic">{job.title}</p>
                    <p className="text-xs text-ink-3 mt-0.5 line-clamp-1">{job.description}</p>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm text-ink-2 font-medium">{job.category}</span>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm font-bold text-ink">Rs. {job.budget}</span>
                </td>
                <td className="px-6 py-4">
                  <span className={`status-${job.status.toLowerCase().replace(' ', '-')}`}>
                    {job.status}
                  </span>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="flex items-center justify-end gap-2">
                    <button className="p-2 hover:bg-surface rounded-lg text-ink-3 hover:text-brand transition-all">
                      <FiEye />
                    </button>
                    <button 
                      className="p-2 hover:bg-red-50 rounded-lg text-ink-3 hover:text-red-500 transition-all"
                      onClick={() => handleDeleteJob(job._id)}
                    >
                      <FiTrash2 />
                    </button>
                  </div>
                </td>
              </tr>
            )) : (
              <tr>
                <td colSpan="5" className="px-6 py-12 text-center text-ink-3 text-sm italic">
                  No jobs found matching your filters
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default JobManagement;
