import React, { useState, useEffect } from 'react';
import { FiCheck, FiX, FiStar, FiShield, FiFileText } from 'react-icons/fi';
import axios from 'axios';
import { toast } from 'react-hot-toast';

const TechnicianManagement = () => {
  const [techs, setTechs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchTechs();
  }, []);

  const fetchTechs = async () => {
    try {
      const res = await axios.get('/api/users');
      setTechs(res.data.filter(u => u.role === 'technician'));
    } catch (err) {
      toast.error('Failed to load technicians');
    } finally {
      setLoading(false);
    }
  };

  const handleVerify = async (id, status) => {
    try {
      // API call to update verification status (I added isVerified to model)
      await axios.patch(`/api/users/${id}`, { isVerified: status });
      toast.success(status ? 'Technician Verified' : 'Verification Revoked');
      fetchTechs();
    } catch (err) {
      toast.error('Failed to update status');
    }
  };

  return (
    <div className="space-y-6 font-body">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {techs.map((tech) => (
          <div key={tech._id} className="card p-6 flex flex-col items-center text-center relative overflow-hidden">
            {tech.isVerified && (
              <div className="absolute top-0 right-0 bg-emerald-500 text-white px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded-bl-xl flex items-center gap-1">
                <FiCheck className="text-xs" /> Verified
              </div>
            )}
            
            <div className="w-20 h-20 rounded-2xl bg-brand/10 border-2 border-brand/20 flex items-center justify-center text-3xl text-brand font-bold mb-4 shadow-inner">
              {tech.name.charAt(0)}
            </div>
            
            <h4 className="font-display font-bold text-lg text-ink italic">{tech.name}</h4>
            <p className="text-xs text-brand font-semibold uppercase tracking-widest mb-4">
              {tech.skills?.[0] || 'General Maintenance'}
            </p>
            
            <div className="flex gap-4 mb-6 w-full px-4">
              <div className="flex-1 bg-surface-alt p-2 rounded-xl border border-outline">
                <p className="text-[10px] text-ink-3 uppercase font-bold">Experience</p>
                <p className="text-sm font-bold text-ink">{tech.experience || 0} Yrs</p>
              </div>
              <div className="flex-1 bg-surface-alt p-2 rounded-xl border border-outline">
                <p className="text-[10px] text-ink-3 uppercase font-bold">Rating</p>
                <div className="flex items-center justify-center gap-1">
                  <FiStar className="text-amber-500 fill-amber-500 text-xs" />
                  <p className="text-sm font-bold text-ink">{tech.rating?.average || '0.0'}</p>
                </div>
              </div>
            </div>

            <div className="flex gap-2 w-full mt-auto">
              {!tech.isVerified ? (
                <button 
                  onClick={() => handleVerify(tech._id, true)}
                  className="flex-1 btn-primary py-2 text-xs flex items-center justify-center gap-2"
                >
                  <FiShield /> Verify Tech
                </button>
              ) : (
                <button 
                  onClick={() => handleVerify(tech._id, false)}
                  className="flex-1 btn-secondary py-2 text-xs border-red-100 text-red-600 hover:bg-red-50"
                >
                  Suspend
                </button>
              )}
              <button className="p-2 btn-secondary hover:text-brand">
                <FiFileText />
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TechnicianManagement;
