import React, { useState, useEffect } from 'react';
import { FiUsers, FiTool, FiCheckCircle, FiClock, FiAlertCircle, FiTrendingUp } from 'react-icons/fi';
import axios from 'axios';

const StatsOverview = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        // Calling the GO service on port 6000
        const res = await axios.get('http://localhost:6000/api/admin/stats');
        setStats(res.data);
      } catch (err) {
        console.error('Failed to fetch stats from Go service:', err);
        // Fallback to mock data for UI demo if service not running
        setStats({
          totalUsers: 125,
          totalHomeowners: 82,
          totalTechnicians: 43,
          totalActiveJobs: 18,
          completedJobs: 156,
          pendingApprovals: 5,
          reportsComplaints: 2,
          revenue: 45200
        });
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  if (loading) return <div className="animate-pulse space-y-8">...Loading Stats</div>;

  const cards = [
    { label: 'Total Users', value: stats.totalUsers, sub: `${stats.totalHomeowners} Homeowners, ${stats.totalTechnicians} Techs`, icon: <FiUsers />, color: 'blue' },
    { label: 'Active Jobs', value: stats.totalActiveJobs, sub: 'Currently in progress', icon: <FiTool />, color: 'amber' },
    { label: 'Completed', value: stats.completedJobs, sub: 'Total successful repairs', icon: <FiCheckCircle />, color: 'emerald' },
    { label: 'Pending Approvals', value: stats.pendingApprovals, sub: 'Technicians awaiting verification', icon: <FiClock />, color: 'purple' },
    { label: 'System Health', value: 'Excellent', sub: `${stats.reportsComplaints} Pending reports`, icon: <FiAlertCircle />, color: 'teal' },
    { label: 'Total Revenue', value: `Rs. ${stats.revenue.toLocaleString()}`, sub: 'Marketplace volume', icon: <FiTrendingUp />, color: 'indigo' },
  ];

  const colorMap = {
    blue: 'bg-blue-50 text-blue-600 border-blue-100',
    amber: 'bg-amber-50 text-amber-600 border-amber-100',
    emerald: 'bg-emerald-50 text-emerald-600 border-emerald-100',
    purple: 'bg-purple-50 text-purple-600 border-purple-100',
    teal: 'bg-teal-50 text-teal-600 border-teal-100',
    indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100',
  };

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {cards.map((card, i) => (
          <div key={i} className="card p-6 flex flex-col gap-4">
            <div className="flex items-start justify-between">
              <div>
                <p className="text-sm font-semibold text-ink-3 uppercase tracking-wider">{card.label}</p>
                <h3 className="text-2xl font-bold text-ink mt-1 italic">{card.value}</h3>
              </div>
              <div className={`p-3 rounded-xl border ${colorMap[card.color]}`}>
                {card.icon}
              </div>
            </div>
            <p className="text-xs text-ink-3">{card.sub}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="card p-6">
          <h4 className="font-display font-bold text-ink mb-6 flex items-center gap-2">
            <FiTrendingUp className="text-brand" />
            Recent Platform Activity
          </h4>
          <div className="space-y-4">
            {[1, 2, 3, 4].map(i => (
              <div key={i} className="flex items-center justify-between py-3 border-b border-outline last:border-0 hover:bg-canvas-alt px-2 rounded-lg transition-all">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-surface-alt border border-outline flex items-center justify-center font-bold text-xs">
                    U{i}
                  </div>
                  <div>
                    <p className="text-sm font-semibold text-ink">New Technician Registered</p>
                    <p className="text-xs text-ink-3">Electrical Specialist from Kathmandu</p>
                  </div>
                </div>
                <span className="text-[10px] bg-brand/10 text-brand px-2 py-0.5 rounded-full font-bold uppercase">2m ago</span>
              </div>
            ))}
          </div>
        </div>

        <div className="card p-6">
          <h4 className="font-display font-bold text-ink mb-6 flex items-center gap-2">
            <FiTool className="text-brand" />
            Active Category Distribution
          </h4>
          <div className="space-y-6">
            <div>
              <div className="flex justify-between text-xs font-semibold mb-1.5 uppercase tracking-wider">
                <span className="text-ink-2">Plumbing</span>
                <span className="text-brand">45%</span>
              </div>
              <div className="h-2 bg-canvas-alt rounded-full overflow-hidden border border-outline">
                <div className="h-full bg-brand rounded-full" style={{ width: '45%' }}></div>
              </div>
            </div>
            <div>
              <div className="flex justify-between text-xs font-semibold mb-1.5 uppercase tracking-wider">
                <span className="text-ink-2">Electrical</span>
                <span className="text-blue-500">30%</span>
              </div>
              <div className="h-2 bg-canvas-alt rounded-full overflow-hidden border border-outline">
                <div className="h-full bg-blue-500 rounded-full" style={{ width: '30%' }}></div>
              </div>
            </div>
            <div>
              <div className="flex justify-between text-xs font-semibold mb-1.5 uppercase tracking-wider">
                <span className="text-ink-2">General Repair</span>
                <span className="text-amber-500">15%</span>
              </div>
              <div className="h-2 bg-canvas-alt rounded-full overflow-hidden border border-outline">
                <div className="h-full bg-amber-500 rounded-full" style={{ width: '15%' }}></div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StatsOverview;
