import React, { useState, useEffect } from 'react';
import { FiSearch, FiMoreVertical, FiUserX, FiCheck, FiMail, FiMapPin } from 'react-icons/fi';
import axios from 'axios';
import { toast } from 'react-hot-toast';

const UserManagement = () => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const res = await axios.get('/api/users');
      setUsers(res.data);
    } catch (err) {
      toast.error('Failed to load users');
    } finally {
      setLoading(false);
    }
  };

  const handleBlockUser = async (id, currentStatus) => {
    try {
      // Logic to block/unblock user
      toast.success(currentStatus ? 'User unblocked' : 'User blocked');
      fetchUsers();
    } catch (err) {
      toast.error('Operation failed');
    }
  };

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(search.toLowerCase()) || 
    u.email.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between bg-surface p-4 rounded-xl border border-outline shadow-sm">
        <div className="relative w-96">
          <FiSearch className="absolute left-3 top-1/2 -translate-y-1/2 text-ink-3" />
          <input 
            type="text" 
            placeholder="Search by name, email..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="input pl-10 h-10 text-sm"
          />
        </div>
        <div className="flex gap-2">
          <button className="btn-secondary py-2 text-xs">Export CSV</button>
          <button className="btn-primary py-2 text-xs">Add New Admin</button>
        </div>
      </div>

      <div className="card overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-surface-alt border-b border-outline">
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-ink-3">User</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-ink-3">Role</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-ink-3">Status</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-ink-3 text-right">Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredUsers.length > 0 ? filteredUsers.map((user) => (
              <tr key={user._id} className="border-b border-outline hover:bg-canvas-alt transition-colors">
                <td className="px-6 py-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-brand/10 border border-brand/20 flex items-center justify-center text-brand font-bold">
                      {user.name.charAt(0)}
                    </div>
                    <div>
                      <p className="font-semibold text-ink">{user.name}</p>
                      <p className="text-xs text-ink-3 flex items-center gap-1">
                        <FiMail className="text-[10px]" /> {user.email}
                      </p>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className={`badge ${
                    user.role === 'admin' ? 'bg-purple-50 text-purple-700' : 
                    user.role === 'technician' ? 'bg-blue-50 text-blue-700' : 'bg-green-50 text-green-700'
                  }`}>
                    {user.role}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                    <span className="text-xs font-semibold text-ink">Active</span>
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="flex items-center justify-end gap-2">
                    <button className="p-2 hover:bg-surface rounded-lg text-ink-3 hover:text-brand transition-all" title="View Profile">
                      <FiSearch />
                    </button>
                    <button 
                      className="p-2 hover:bg-red-50 rounded-lg text-ink-3 hover:text-red-500 transition-all" 
                      title="Block User"
                      onClick={() => handleBlockUser(user._id, false)}
                    >
                      <FiUserX />
                    </button>
                  </div>
                </td>
              </tr>
            )) : (
              <tr>
                <td colSpan="4" className="px-6 py-12 text-center text-ink-3 text-sm italic">
                  No users found matching your search criteria
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default UserManagement;
